package bmmgen

import (
	"bytes"
	"cmp"
	"fmt"
	"go/format"
	"maps"
	"slices"
	"strings"

	"github.com/cadasto/openehr-sdk-go/openehr/bmm"
)

// renderGeneratedHeader builds the file-level header (DO NOT EDIT
// banner + Source label + package clause) for the supplied plan's
// target. Phase 2 used a fixed string constant; Phase 4 parameterises
// it per target so AOM and RM both round-trip deterministically.
func renderGeneratedHeader(plan *Plan) string {
	return "// Code generated by bmmgen; DO NOT EDIT.\n" +
		"// Source: " + plan.Target.SourceLabel + "\n" +
		"\n" +
		"package " + plan.Target.GoPackage + "\n"
}

// RenderFile renders one [PlannedFile] to a gofmt-canonical byte
// slice. Cross-file context (other classes, package paths) is taken
// from the supplied [Plan].
func RenderFile(plan *Plan, file *PlannedFile) ([]byte, error) {
	var body bytes.Buffer
	body.WriteString(renderGeneratedHeader(plan))
	body.WriteString("\n")

	// Pre-render class bodies so we can detect whether any of them
	// emit a cross-target reference (qualified with the target's
	// ExternalQualifier). If so, we need to add the import.
	var classChunks []string
	for _, pc := range file.Classes {
		chunk, err := renderClass(plan, pc)
		if err != nil {
			return nil, fmt.Errorf("render %s: %w", pc.BMMName, err)
		}
		classChunks = append(classChunks, chunk)
	}

	if needsExternalImport(plan, classChunks) {
		fmt.Fprintf(&body, "import %q\n\n", plan.Target.ExternalImport)
	}

	// File-level comment recording the BMM package this corresponds
	// to. Keeps reviewers oriented.
	if file.PackagePath != "" {
		fmt.Fprintf(&body, "// BMM package: %s\n\n", file.PackagePath)
	} else {
		body.WriteString("// BMM package: (foundation classes)\n\n")
	}

	for _, chunk := range classChunks {
		body.WriteString(chunk)
		body.WriteString("\n")
	}

	formatted, err := format.Source(body.Bytes())
	if err != nil {
		// Return the unformatted source in the error to ease debugging.
		return body.Bytes(), fmt.Errorf("gofmt %s_gen.go: %w", file.FileBase, err)
	}
	return formatted, nil
}

// needsExternalImport returns true if any of the rendered class
// chunks contains a "<qualifier>." token that would require importing
// the target's ExternalImport. Trivial implementation — searches for
// the qualifier followed by '.' in each chunk. Safe because the only
// way this token enters generated source is via cross-target
// references.
func needsExternalImport(plan *Plan, chunks []string) bool {
	if plan.Target.ExternalQualifier == "" || plan.Target.ExternalImport == "" {
		return false
	}
	needle := plan.Target.ExternalQualifier + "."
	for _, c := range chunks {
		if strings.Contains(c, needle) {
			return true
		}
	}
	return false
}

// RenderTypeRegFile renders <pkg>/typereg_gen.go containing
// init() registrations for every concrete class owned by the plan's
// target. The file lives inside the target's Go package; it imports
// the shared rm/typereg subpackage (the registry is shared between
// RM and AOM — _type strings are disjoint).
func RenderTypeRegFile(plan *Plan) ([]byte, error) {
	var b bytes.Buffer
	b.WriteString(renderGeneratedHeader(plan))
	b.WriteString("\n")
	fmt.Fprintf(&b, "import %q\n\n", plan.Target.RegistryImport)
	b.WriteString("func init() {\n")
	// Stable order: by BMM name.
	concrete := append([]*PlannedClass(nil), plan.ConcreteClasses...)
	slices.SortFunc(concrete, func(a, b *PlannedClass) int { return cmp.Compare(a.BMMName, b.BMMName) })
	for _, pc := range concrete {
		goType := pc.GoName
		if sc, ok := pc.Class.(*bmm.SimpleClass); ok && sc.IsGeneric() {
			goType = pc.GoName + defaultGenericArgs(plan, sc)
		}
		fmt.Fprintf(&b, "\ttypereg.Default.Register(%q, func() any { return &%s{} })\n", pc.BMMName, goType)
	}
	b.WriteString("}\n")
	// Reverse registry + nil predicate (ADR 0013) — RM target only:
	// the identity consumers live against the RM model, and the AOM
	// target has no equivalent surface.
	if plan.Target.GoPackage == "rm" {
		if err := emitReverseRegistry(&b, plan, concrete); err != nil {
			return nil, err
		}
	}
	formatted, err := format.Source(b.Bytes())
	if err != nil {
		return b.Bytes(), fmt.Errorf("gofmt typereg_gen.go: %w", err)
	}
	return formatted, nil
}

// codecPolymorphicAbstractGenericNames lists abstract generic BMM
// classes emitted as marker interfaces for JSON polymorphism (ADR 0003).
// Additional classes (e.g. VERSION) need separate design before widening.
var codecPolymorphicAbstractGenericNames = map[string]bool{
	"EVENT": true,
}

// codecPolymorphicAbstractGeneric reports whether the planned class
// is whitelisted for codec-facing interface emission.
func codecPolymorphicAbstractGeneric(plan *Plan, pc *PlannedClass) bool {
	return codecPolymorphicAbstractGenericNames[pc.BMMName]
}

// renderClass dispatches on the planned class's BMM kind.
//
// Abstract classes become Go interfaces with an is<X>() marker;
// concrete descendants gain the marker method (see renderAbstractClass).
// Abstract + generic classes without concrete descendants (e.g. some
// internal generic bases) remain structs. Abstract + generic classes
// with concrete descendants (EVENT, VERSION, …) become interfaces per
// ADR 0003 so codec polymorphism works at List<Event> sites.
func renderClass(plan *Plan, pc *PlannedClass) (string, error) {
	switch cls := pc.Class.(type) {
	case *bmm.Enumeration:
		return renderEnumeration(plan, pc, cls)
	case *bmm.Interface:
		return renderInterface(plan, pc, cls)
	case *bmm.SimpleClass:
		if cls.IsAbstract() && (!cls.IsGeneric() || codecPolymorphicAbstractGeneric(plan, pc)) {
			return renderAbstractClass(plan, pc, cls)
		}
		return renderConcreteClass(plan, pc, cls)
	default:
		return "", fmt.Errorf("unhandled BMM class kind %T for %s", cls, pc.BMMName)
	}
}

// renderEnumeration emits `type X <int|string>` plus a const block.
// item_values are honoured for integer enums; for string enums the
// values default to the item_names (per the BMM persistence rules).
func renderEnumeration(_ *Plan, pc *PlannedClass, e *bmm.Enumeration) (string, error) {
	var b strings.Builder
	writeDoc(&b, pc.GoName, e.Documentation())
	switch {
	case e.IsIntegerEnum():
		fmt.Fprintf(&b, "type %s int32\n", pc.GoName)
		b.WriteString("\nconst (\n")
		for i, n := range e.ItemNames {
			val := int64(i)
			if i < len(e.ItemValuesInt) {
				val = e.ItemValuesInt[i]
			}
			doc := ""
			if i < len(e.ItemDocumentations) {
				doc = e.ItemDocumentations[i]
			}
			if doc != "" {
				writeIndentedDoc(&b, "\t", enumConstName(pc.GoName, n), doc)
			}
			fmt.Fprintf(&b, "\t%s %s = %d\n", enumConstName(pc.GoName, n), pc.GoName, val)
		}
		b.WriteString(")\n")
	default:
		// string enum
		fmt.Fprintf(&b, "type %s string\n", pc.GoName)
		b.WriteString("\nconst (\n")
		for i, n := range e.ItemNames {
			val := n
			if i < len(e.ItemValuesString) {
				val = e.ItemValuesString[i]
			}
			doc := ""
			if i < len(e.ItemDocumentations) {
				doc = e.ItemDocumentations[i]
			}
			if doc != "" {
				writeIndentedDoc(&b, "\t", enumConstName(pc.GoName, n), doc)
			}
			fmt.Fprintf(&b, "\t%s %s = %q\n", enumConstName(pc.GoName, n), pc.GoName, val)
		}
		b.WriteString(")\n")
	}
	return b.String(), nil
}

func enumConstName(typeName, item string) string {
	// Concatenate the type name + PascalCase(item). E.g. PROPORTION_KIND
	// + "pk_ratio" -> "ProportionKindPkRatio".
	return typeName + PascalCase(item)
}

// renderInterface emits `type X interface { ... }` with the
// marker method is<X>(). Functions on the interface are emitted as
// concrete method stubs on each non-overriding descendant (see
// [renderFunctions]). The Go interface stays marker-only in v1 to
// avoid the signature-mismatch fan-out caused by BMM
// covariant-return / contravariant-parameter overrides.
func renderInterface(plan *Plan, pc *PlannedClass, _ *bmm.Interface) (string, error) {
	var b strings.Builder
	writeDoc(&b, pc.GoName, pc.Class.Documentation())
	fmt.Fprintf(&b, "type %s interface {\n", pc.GoName)
	fmt.Fprintf(&b, "\tis%s()\n", pc.GoName)
	b.WriteString("}\n")
	// Marker methods on concrete descendants.
	emitMarkerMethods(&b, plan, pc)
	// Phase-3 method stubs (the P_BMM_INTERFACE may also declare
	// functions; they propagate to concrete descendants).
	if err := renderFunctions(&b, plan, pc); err != nil {
		return "", err
	}
	return b.String(), nil
}

// emitMarkerMethods writes one `func (Descendant) is<X>() {}` line
// per concrete descendant. Marker methods use *value* receivers so
// the interface is satisfied by both `T` and `*T` — this matters
// when a generic class constrains its type parameter to the
// interface (e.g. `DVInterval[T DVOrdered]`) and the consumer binds
// it to a value type. Generic descendants get a generic receiver
// expression — handled by [genericReceiverParams].
func emitMarkerMethods(b *strings.Builder, plan *Plan, pc *PlannedClass) {
	for _, dn := range plan.AbstractDescendants[pc.BMMName] {
		dc, ok := plan.Classes[dn]
		if !ok {
			continue
		}
		desc, isSimple := dc.Class.(*bmm.SimpleClass)
		if !isSimple {
			continue
		}
		recv := dc.GoName + genericReceiverParams(desc)
		fmt.Fprintf(b, "\nfunc (%s) is%s() {}\n", recv, pc.GoName)
	}
}

// genericReceiverParams returns "[T, K]" (etc.) when the class is
// generic, or "" otherwise. Used so generic-class marker methods
// declare proper generic receivers.
func genericReceiverParams(sc *bmm.SimpleClass) string {
	if !sc.IsGeneric() {
		return ""
	}
	keys := sortedStringKeys(sc.GenericParameterDefs)
	return "[" + strings.Join(keys, ", ") + "]"
}

// renderAbstractClass emits an interface for the abstract class
// (marker pattern). Marker methods on every concrete descendant get
// emitted alongside. We do not lift the abstract class's properties
// into the interface — fields are carried by embedded ancestor
// structs at the concrete sites, and renderConcreteClass handles
// that.
func renderAbstractClass(plan *Plan, pc *PlannedClass, _ *bmm.SimpleClass) (string, error) {
	var b strings.Builder
	writeDoc(&b, pc.GoName, pc.Class.Documentation())
	fmt.Fprintf(&b, "type %s interface {\n", pc.GoName)
	fmt.Fprintf(&b, "\tis%s()\n", pc.GoName)
	// LOCATABLE identity surface (ADR 0013): the sealed interface is
	// widened with the generated Get<Field> accessors.
	if pc.BMMName == locatableClassName && !pc.External {
		if err := emitLocatableGetterSignatures(&b, plan, pc); err != nil {
			return "", err
		}
	}
	b.WriteString("}\n")
	emitMarkerMethods(&b, plan, pc)
	if pc.BMMName == locatableClassName && !pc.External {
		if err := emitLocatableIdentity(&b, plan, pc); err != nil {
			return "", err
		}
	}
	// Phase-3: methods declared on this abstract class are emitted as
	// concrete stubs on each descendant that does not override them
	// (the Go interface stays marker-only).
	if err := renderFunctions(&b, plan, pc); err != nil {
		return "", err
	}
	return b.String(), nil
}

// renderConcreteClass emits a concrete struct with:
//   - Properties from the class itself, plus the transitive union of
//     all properties contributed by abstract ancestors (flattened in
//     declaration site). Concrete ancestors (rare) are embedded by
//     name.
//   - Properties in alphabetical order by effective name.
//   - Generic class parameters when the BMM class declares them.
//
// Why flattening, not embedding: per § Naming and § Embedded
// ancestors in the Phase 2 spec, abstract classes are interfaces
// (with is<X>() markers). Concrete classes therefore cannot embed
// their immediate abstract ancestor (an interface carries no data).
// Flattening preserves the field set; the polymorphism markers in
// [renderAbstractClass] / [renderInterface] provide the interface
// satisfaction.
func renderConcreteClass(plan *Plan, pc *PlannedClass, sc *bmm.SimpleClass) (string, error) {
	var b strings.Builder
	writeDoc(&b, pc.GoName, pc.Class.Documentation())
	// Generic class — emit type parameters.
	typeParams := ""
	if sc.IsGeneric() {
		typeParams = genericClassParamList(plan, sc)
	}
	fmt.Fprintf(&b, "type %s%s struct {\n", pc.GoName, typeParams)

	// Concrete ancestor embeds. Walk ancestors in declaration order;
	// embed each ancestor that is rendered as a struct (concrete OR
	// abstract+generic — see [renderClass] for why generic-abstract
	// classes become structs). Pure abstract ancestors (interfaces)
	// are flattened by [collectFlattenedProperties] further down.
	embedded := map[string]bool{}
	for _, anc := range pc.Class.Ancestors() {
		if isPrimitive(anc) || isSkippedPrimitive(anc) {
			continue
		}
		ap, ok := plan.Classes[anc]
		if !ok {
			continue
		}
		acls, isSimple := ap.Class.(*bmm.SimpleClass)
		if !isSimple {
			continue
		}
		isStruct := !acls.IsAbstract() || (acls.IsGeneric() && !codecPolymorphicAbstractGeneric(plan, ap))
		if !isStruct {
			continue
		}
		ancRef := qualifyClassRef(plan, ap)
		switch {
		case acls.IsGeneric() && len(acls.GenericParameterDefs) == len(sc.GenericParameterDefs):
			// Same arity — forward the descendant's parameter names.
			fmt.Fprintf(&b, "\t%s%s\n", ancRef, genericInstantiationFromDescendant(sc))
		case acls.IsGeneric():
			// Different arity — fall back to default-instantiation
			// using the ancestor's own bounds.
			fmt.Fprintf(&b, "\t%s%s\n", ancRef, defaultGenericArgs(plan, acls))
		default:
			fmt.Fprintf(&b, "\t%s\n", ancRef)
		}
		embedded[anc] = true
	}

	// Collect own + abstract-ancestor properties (transitive). If a
	// property is shadowed by a name match at a deeper-in-the-tree
	// level (Go embedding-promotion rules wouldn't help here because
	// we're flattening, not embedding), the descendant wins.
	props := collectFlattenedProperties(plan, sc, embedded)

	keys := make([]string, 0, len(props))
	for k := range props {
		keys = append(keys, k)
	}
	slices.Sort(keys)
	for _, name := range keys {
		prop := props[name]
		field, err := renderField(plan, sc, pc.BMMName, prop)
		if err != nil {
			return "", err
		}
		b.WriteString(field)
	}
	b.WriteString("}\n")
	// REQ-052 narrow `<GoName>Like` interfaces were previously
	// emitted here. They now live in the non-generated
	// `openehr/rm/like_interfaces.go` so callers can use RM-shaped
	// accessor methods (GetValue, GetDefiningCode, …) without the
	// codegen growing a per-class method-body table. plan.ConcreteSubtypes
	// remains the source of truth for field-type lifting (see
	// singleTypeRef and polymorphicProperty); only the interface
	// declaration + marker methods moved out.
	// Phase-3: emit method stubs for any functions declared on this
	// class. For abstract+generic structs (e.g. EVENT[T]) this also
	// emits the class's own functions on the embedding receiver.
	if err := renderFunctions(&b, plan, pc); err != nil {
		return "", err
	}
	return b.String(), nil
}

// collectFlattenedProperties returns the union of the class's own
// properties plus the properties of every abstract ancestor visited
// transitively. Concrete ancestors (already embedded) are excluded —
// their fields come through Go embedding-promotion. The descendant
// wins on name collisions (closer wins).
func collectFlattenedProperties(plan *Plan, sc *bmm.SimpleClass, embedded map[string]bool) map[string]bmm.Property {
	result := map[string]bmm.Property{}
	// Walk ancestors first so the descendant overrides.
	var walk func(c bmm.Class)
	visited := map[string]bool{}
	walk = func(c bmm.Class) {
		for _, anc := range c.Ancestors() {
			if visited[anc] || embedded[anc] {
				continue
			}
			visited[anc] = true
			ap, ok := plan.Classes[anc]
			if !ok {
				continue
			}
			ascls, isSimple := ap.Class.(*bmm.SimpleClass)
			if !isSimple {
				continue
			}
			if !ascls.IsAbstract() {
				// Concrete (non-embedded) ancestor — skip; either
				// already embedded, or skipped at the use-site.
				continue
			}
			for name, p := range ascls.Properties {
				if _, exists := result[name]; !exists {
					result[name] = p
				}
			}
			walk(ascls)
		}
	}
	walk(sc)
	// Own properties override.
	maps.Copy(result, sc.Properties)
	return result
}

// collectFlattenedPropertyOrder returns property names for a concrete
// class in BMM declaration order: abstract-ancestor properties first
// (each ancestor's PropertyOrder), then the class's own properties.
// When the class shadows an ancestor property, the name moves to the
// class's own declaration position.
func collectFlattenedPropertyOrder(plan *Plan, sc *bmm.SimpleClass, embedded map[string]bool) []string {
	props := collectFlattenedProperties(plan, sc, embedded)
	var order []string
	seen := map[string]bool{}
	remove := func(name string) {
		for i, n := range order {
			if n == name {
				order = append(order[:i], order[i+1:]...)
				return
			}
		}
	}
	addFrom := func(cls *bmm.SimpleClass) {
		for _, name := range propertyNamesInOrder(cls) {
			if _, ok := props[name]; !ok {
				continue
			}
			if seen[name] {
				remove(name)
			}
			seen[name] = true
			order = append(order, name)
		}
	}
	var walk func(c bmm.Class)
	visited := map[string]bool{}
	walk = func(c bmm.Class) {
		for _, anc := range c.Ancestors() {
			if visited[anc] || embedded[anc] {
				continue
			}
			visited[anc] = true
			ap, ok := plan.Classes[anc]
			if !ok {
				continue
			}
			ascls, isSimple := ap.Class.(*bmm.SimpleClass)
			if !isSimple || !ascls.IsAbstract() {
				continue
			}
			addFrom(ascls)
			walk(ascls)
		}
	}
	walk(sc)
	addFrom(sc)
	return order
}

func propertyNamesInOrder(sc *bmm.SimpleClass) []string {
	if len(sc.PropertyOrder) > 0 {
		return sc.PropertyOrder
	}
	return sortedStringKeys(sc.Properties)
}

// genericClassParamList renders a `[T any, K comparable, ...]` type
// parameter list from a generic class's GenericParameterDefs.
// Ordering is alphabetical for determinism.
//
// If a descendant's generic param def omits conforms_to_type, the
// constraint is inherited from the nearest ancestor that declares
// one for the same parameter name (BMM convention: the constraint
// is set once on the abstract generic ancestor and re-used).
func genericClassParamList(plan *Plan, sc *bmm.SimpleClass) string {
	if len(sc.GenericParameterDefs) == 0 {
		return ""
	}
	keys := sortedStringKeys(sc.GenericParameterDefs)
	var parts []string
	for _, k := range keys {
		def := sc.GenericParameterDefs[k]
		bound := def.ConformsToType
		if bound == "" {
			bound = inheritedGenericBound(plan, sc, k)
		}
		constraint := boundToGoConstraint(plan, bound)
		parts = append(parts, fmt.Sprintf("%s %s", k, constraint))
	}
	return "[" + strings.Join(parts, ", ") + "]"
}

// boundToGoConstraint maps a BMM bound name to a Go constraint
// expression. Returns "any" for missing / unresolvable / "Any"
// bounds. Cross-target references are qualified with the target's
// ExternalQualifier.
func boundToGoConstraint(plan *Plan, bound string) string {
	if bound == "" || bound == "Any" {
		return "any"
	}
	if isPrimitive(bound) {
		return "any"
	}
	if pc, ok := plan.Classes[bound]; ok {
		switch cls := pc.Class.(type) {
		case *bmm.Interface:
			return qualifyClassRef(plan, pc)
		case *bmm.SimpleClass:
			if cls.IsAbstract() && !cls.IsGeneric() {
				return qualifyClassRef(plan, pc)
			}
		}
	}
	return "any"
}

// inheritedGenericBound walks the BMM ancestor chain of sc and
// returns the conforms_to_type for the generic parameter named
// paramName, taken from the nearest ancestor that declares it.
// Returns "" if no ancestor has a binding.
func inheritedGenericBound(plan *Plan, sc *bmm.SimpleClass, paramName string) string {
	visited := map[string]bool{}
	var walk func(c bmm.Class) string
	walk = func(c bmm.Class) string {
		for _, anc := range c.Ancestors() {
			if visited[anc] {
				continue
			}
			visited[anc] = true
			ap, ok := plan.Classes[anc]
			if !ok {
				continue
			}
			scAnc, isSimple := ap.Class.(*bmm.SimpleClass)
			if !isSimple {
				continue
			}
			if scAnc.GenericParameterDefs != nil {
				if def, ok := scAnc.GenericParameterDefs[paramName]; ok && def.ConformsToType != "" {
					return def.ConformsToType
				}
			}
			if v := walk(scAnc); v != "" {
				return v
			}
		}
		return ""
	}
	return walk(sc)
}

// genericInstantiationFromDescendant returns a `[T, K]` parameter
// list mirroring the descendant's own generic parameter defs.
// Useful when an embedded generic ancestor takes the same
// parameters as the descendant (e.g. Point_interval[T] embedding
// Interval[T]).
func genericInstantiationFromDescendant(sc *bmm.SimpleClass) string {
	if len(sc.GenericParameterDefs) == 0 {
		return ""
	}
	keys := sortedStringKeys(sc.GenericParameterDefs)
	return "[" + strings.Join(keys, ", ") + "]"
}

// renderField emits one struct-field line for one BMM property.
// ownerName is the BMM name of the class that owns this field (used
// for cyclic-pointer lookup).
func renderField(plan *Plan, owner *bmm.SimpleClass, ownerName string, prop bmm.Property) (string, error) {
	name := prop.PropertyName()
	goName := FieldName(name)
	jsonTag := fmt.Sprintf("`json:%q`", name)
	jsonTagOpt := fmt.Sprintf("`json:%q`", name+",omitempty")

	docLines := propertyDoc(goName, propertyDocText(prop))

	switch p := prop.(type) {
	case *bmm.SingleProperty:
		ref, err := singlePropTypeExpr(plan, owner, ownerName, p)
		if err != nil {
			return "", err
		}
		if p.IsMandatory {
			return docLines + fmt.Sprintf("\t%s %s %s\n", goName, ref, jsonTag), nil
		}
		return docLines + fmt.Sprintf("\t%s %s %s\n", goName, ref, jsonTagOpt), nil

	case *bmm.SinglePropertyOpen:
		// Open generic parameter: emit the type name verbatim — it
		// refers to a class-level type parameter.
		typ := p.TypeName
		tag := jsonTag
		if !p.IsMandatory {
			tag = jsonTagOpt
		}
		return docLines + fmt.Sprintf("\t%s %s %s\n", goName, typ, tag), nil

	case *bmm.ContainerProperty:
		inner, err := containerInner(plan, owner, p.TypeDef)
		if err != nil {
			return "", err
		}
		fieldType, tag := containerFieldShape(p.TypeDef, inner, jsonTag, jsonTagOpt, p.Cardinality)
		return docLines + fmt.Sprintf("\t%s %s %s\n", goName, fieldType, tag), nil

	case *bmm.GenericProperty:
		typ, err := genericTypeRef(plan, owner, p.TypeDef)
		if err != nil {
			return "", err
		}
		tag := jsonTag
		ref := typ
		if !p.IsMandatory {
			tag = jsonTagOpt
			ref = "*" + typ
		}
		return docLines + fmt.Sprintf("\t%s %s %s\n", goName, ref, tag), nil

	default:
		return "", fmt.Errorf("unhandled property kind %T for %s", p, name)
	}
}

// containerFieldShape converts a BMM container TypeDef + cardinality
// into a Go field-type string (either []T or map[K]V) and chooses
// the appropriate JSON tag. omitempty is applied when the container
// is optional (cardinality.lower == 0 or absent).
func containerFieldShape(td *bmm.ContainerType, inner, mandatoryTag, optTag string, card *bmm.Cardinality) (string, string) {
	tag := mandatoryTag
	if card == nil || card.Lower == 0 {
		tag = optTag
	}
	if td == nil {
		return "[]" + inner, tag
	}
	switch td.ContainerType {
	case "Hash":
		// Hash<K,V> in the BMM has K = string typically. We emit
		// map[string]V because BMM Hash keys are not richly typed in
		// the property's type_def — they're parameterised in the
		// generic class. inner is the value type.
		return "map[string]" + inner, tag
	case "List", "Set", "Array":
		return "[]" + inner, tag
	default:
		return "[]" + inner, tag
	}
}

// containerInner resolves the Go type expression for the *element*
// of a container property's type_def.
func containerInner(plan *Plan, owner *bmm.SimpleClass, td *bmm.ContainerType) (string, error) {
	if td == nil || td.TypeDef == nil {
		return "any", nil
	}
	return typeRef(plan, owner, td.TypeDef)
}

// genericTypeRef resolves a GenericProperty's type_def to a Go type
// expression like `DVInterval[DVQuantity]`.
//
// Special-case for container kinds: when the root_type is Hash,
// List, Set, or Array the result is the Go shorthand (`map[K]V`,
// `[]T`) rather than a generic Go-type instantiation. Per
// docs/specifications/bmm-conformance.md § Container mapping.
func genericTypeRef(plan *Plan, owner *bmm.SimpleClass, gt *bmm.GenericType) (string, error) {
	if gt == nil {
		return "any", nil
	}
	// Container-kind specialisation.
	if containerKinds[gt.RootType] {
		params := gt.GenericParameters
		switch gt.RootType {
		case "Hash":
			keyRef := "string"
			valRef := "any"
			if len(params) >= 2 {
				k, err := typeRef(plan, owner, params[0])
				if err != nil {
					return "", err
				}
				v, err := typeRef(plan, owner, params[1])
				if err != nil {
					return "", err
				}
				keyRef, valRef = k, v
			} else if len(params) == 1 {
				v, err := typeRef(plan, owner, params[0])
				if err != nil {
					return "", err
				}
				valRef = v
			}
			return "map[" + keyRef + "]" + valRef, nil
		case "List", "Set", "Array":
			inner := "any"
			if len(params) == 1 {
				r, err := typeRef(plan, owner, params[0])
				if err != nil {
					return "", err
				}
				inner = r
			}
			return "[]" + inner, nil
		}
	}

	if pc, ok := plan.Classes[gt.RootType]; ok && codecPolymorphicAbstractGeneric(plan, pc) {
		return qualifyClassRef(plan, pc), nil
	}
	root := goNameForRef(plan, gt.RootType)
	if root == "" {
		root = "any"
	}
	if len(gt.GenericParameters) == 0 {
		return root, nil
	}
	parts := make([]string, 0, len(gt.GenericParameters))
	for _, pp := range gt.GenericParameters {
		ref, err := typeRef(plan, owner, pp)
		if err != nil {
			return "", err
		}
		parts = append(parts, ref)
	}
	return root + "[" + strings.Join(parts, ", ") + "]", nil
}

// typeRef resolves an arbitrary BMM Type (Simple/Generic/Container)
// to a Go type expression at use-site.
func typeRef(plan *Plan, owner *bmm.SimpleClass, t bmm.Type) (string, error) {
	switch v := t.(type) {
	case *bmm.SimpleType:
		// Could be a primitive name, a class name, or an open generic
		// parameter on the owning class.
		if owner != nil && owner.GenericParameterDefs != nil {
			if _, ok := owner.GenericParameterDefs[v.TypeName]; ok {
				return v.TypeName, nil
			}
		}
		ref, _, err := singleTypeRef(plan, owner, v.TypeName)
		return ref, err
	case *bmm.GenericType:
		return genericTypeRef(plan, owner, v)
	case *bmm.ContainerType:
		inner, err := containerInner(plan, owner, v)
		if err != nil {
			return "", err
		}
		switch v.ContainerType {
		case "Hash":
			return "map[string]" + inner, nil
		default:
			return "[]" + inner, nil
		}
	default:
		return "any", nil
	}
}

// singleTypeRef resolves a bare type name. The second return is true
// when the name resolves to a planned class (vs a Go primitive).
//
// If the referenced class is generic but the SimpleProperty type
// reference omits parameters (a common BMM idiom for an abstract
// generic ancestor), the function fills in the parameter list using
// the class's declared generic parameter bounds (or `any` when the
// bound is `Any` / empty / not resolvable to a Go interface).
// singlePropTypeExpr resolves the Go type expression for a single
// (non-container) property exactly as struct-field rendering does:
// mandatory properties keep the bare type (cycle-broken to a pointer
// when in the mutual-recursion graph); optional properties become
// pointers unless the type resolves to an interface (interfaces are
// nilable already). Shared by [renderField] and the LOCATABLE identity
// emission (render_identity.go) so accessor types cannot drift from
// field declarations.
func singlePropTypeExpr(plan *Plan, owner *bmm.SimpleClass, ownerName string, p *bmm.SingleProperty) (string, error) {
	typ, _, err := singleTypeRef(plan, owner, p.TypeName)
	if err != nil {
		return "", err
	}
	name := p.PropertyName()
	if p.IsMandatory {
		// Cycle-break: when this owner/prop is in the mutual
		// recursion graph, force a pointer so the Go compiler
		// accepts the struct definition.
		if plan.CyclicSingleProps[ownerName][name] {
			return "*" + typ, nil
		}
		return typ, nil
	}
	// optional — pointer for nullability unless the type is an
	// interface (interface fields are nilable already).
	if !isInterfaceTypeRef(plan, p.TypeName) {
		return "*" + typ, nil
	}
	return typ, nil
}

func singleTypeRef(plan *Plan, owner *bmm.SimpleClass, name string) (string, bool, error) {
	// Open generic parameter on the owning class wins first.
	if owner != nil && owner.GenericParameterDefs != nil {
		if _, ok := owner.GenericParameterDefs[name]; ok {
			return name, false, nil
		}
	}
	if isPrimitive(name) {
		return primitiveGoType[name], false, nil
	}
	if isSkippedPrimitive(name) || isSkippedClass(name) {
		return "any /* TODO: unmapped " + name + " */", false, nil
	}
	if pc, ok := plan.Classes[name]; ok {
		if codecPolymorphicAbstractGeneric(plan, pc) {
			return qualifyClassRef(plan, pc), true, nil
		}
		// Generic class without explicit args — default-instantiate.
		if sc, isSimple := pc.Class.(*bmm.SimpleClass); isSimple && sc.IsGeneric() {
			return qualifyClassRef(plan, pc) + defaultGenericArgs(plan, sc), true, nil
		}
		// REQ-052: concrete class with registered subtypes is lifted
		// to a narrow `<Parent>Like` Go interface. The struct field
		// adopts the interface so the wire-decode dispatch via typereg
		// is lossless across subtype payloads.
		if iface, ok := narrowInterfaceGoName(plan, name); ok {
			return iface, true, nil
		}
		return qualifyClassRef(plan, pc), true, nil
	}
	// Unknown — fall through to `any` with a TODO. Caller should
	// surface a Note in the plan; we keep going so the file
	// compiles.
	return "any /* TODO: unknown type " + name + " */", false, nil
}

// qualifyClassRef returns the Go-source expression for a class
// reference. Owned classes are returned unqualified; external
// classes are prefixed with the target's ExternalQualifier
// (e.g. "rm.AuthoredResource").
func qualifyClassRef(plan *Plan, pc *PlannedClass) string {
	if pc.External && plan.Target.ExternalQualifier != "" {
		return plan.Target.ExternalQualifier + "." + pc.GoName
	}
	return pc.GoName
}

// defaultGenericArgs returns a "[arg1, arg2]" Go-source instantiation
// for a generic class when the caller had no parameter list to bind.
// Each arg is the Go form of the bound's `conforms_to_type` (mapped
// through the planned class set), defaulting to `any` for "Any" or
// missing bounds. Argument order matches the alphabetic key order of
// GenericParameterDefs. Cross-target references are qualified.
func defaultGenericArgs(plan *Plan, sc *bmm.SimpleClass) string {
	keys := sortedStringKeys(sc.GenericParameterDefs)
	parts := make([]string, 0, len(keys))
	for _, k := range keys {
		def := sc.GenericParameterDefs[k]
		bound := def.ConformsToType
		if bound == "" {
			bound = inheritedGenericBound(plan, sc, k)
		}
		if bound == "" || bound == "Any" {
			parts = append(parts, "any")
			continue
		}
		if isPrimitive(bound) {
			parts = append(parts, primitiveGoType[bound])
			continue
		}
		if pc, ok := plan.Classes[bound]; ok {
			parts = append(parts, qualifyClassRef(plan, pc))
			continue
		}
		parts = append(parts, "any")
	}
	return "[" + strings.Join(parts, ", ") + "]"
}

// goNameForRef returns the Go name for a BMM type reference (class
// or primitive) at a use site where the caller will append its own
// generic instantiation. Used by genericTypeRef to assemble
// `RootName[Arg1, Arg2]` — so we deliberately do NOT inject default
// generic args here. Cross-target references are qualified with the
// target's ExternalQualifier (e.g. "rm.").
//
// Returns the Go primitive for primitives, the planned Go name for a
// class, or "" when unknown.
func goNameForRef(plan *Plan, name string) string {
	if isPrimitive(name) {
		return primitiveGoType[name]
	}
	if pc, ok := plan.Classes[name]; ok {
		return qualifyClassRef(plan, pc)
	}
	return ""
}

// isInterfaceTypeRef reports whether the named BMM class resolves to
// an interface in the generated Go code (abstract class, P_BMM_INTERFACE,
// or a concrete-with-subtypes parent lifted to a narrow `<Parent>Like`
// interface per REQ-052). Optional properties typed by an interface
// do NOT need an extra `*` indirection.
func isInterfaceTypeRef(plan *Plan, name string) bool {
	pc, ok := plan.Classes[name]
	if !ok {
		return false
	}
	switch cls := pc.Class.(type) {
	case *bmm.Interface:
		return true
	case *bmm.SimpleClass:
		if cls.IsAbstract() && (!cls.IsGeneric() || codecPolymorphicAbstractGeneric(plan, pc)) {
			return true
		}
		// Concrete-with-subtypes — emitted as a narrow Go interface.
		if _, hasKids := plan.ConcreteSubtypes[pc.BMMName]; hasKids && !cls.IsGeneric() && !pc.IsPrimitive {
			return true
		}
	}
	return false
}

// propertyDocText extracts the documentation string from any
// Property variant. The bmm.Property interface itself does not
// expose Documentation, so we switch on the concrete type.
func propertyDocText(p bmm.Property) string {
	switch v := p.(type) {
	case *bmm.SingleProperty:
		return v.Documentation
	case *bmm.SinglePropertyOpen:
		return v.Documentation
	case *bmm.ContainerProperty:
		return v.Documentation
	case *bmm.GenericProperty:
		return v.Documentation
	}
	return ""
}

// writeDoc writes a Go-doc-style comment block before a top-level
// declaration named goName. The first line of the doc is the BMM
// documentation, prefixed with `<goName>` so godoc parses it
// correctly.
func writeDoc(b *strings.Builder, goName, doc string) {
	doc = cleanDoc(doc)
	if doc == "" {
		fmt.Fprintf(b, "// %s is generated from a BMM class.\n", goName)
		return
	}
	lines := strings.Split(doc, "\n")
	if len(lines) == 0 {
		fmt.Fprintf(b, "// %s is generated from a BMM class.\n", goName)
		return
	}
	fmt.Fprintf(b, "// %s %s\n", goName, lines[0])
	for _, l := range lines[1:] {
		if l == "" {
			b.WriteString("//\n")
		} else {
			fmt.Fprintf(b, "// %s\n", l)
		}
	}
}

// writeIndentedDoc writes a Go-doc comment block with an indentation
// prefix (used inside const blocks).
func writeIndentedDoc(b *strings.Builder, indent, goName, doc string) {
	doc = cleanDoc(doc)
	if doc == "" {
		return
	}
	lines := strings.Split(doc, "\n")
	fmt.Fprintf(b, "%s// %s %s\n", indent, goName, lines[0])
	for _, l := range lines[1:] {
		if l == "" {
			fmt.Fprintf(b, "%s//\n", indent)
		} else {
			fmt.Fprintf(b, "%s// %s\n", indent, l)
		}
	}
}

// propertyDoc emits a struct-field doc comment block (indented with
// a tab). The first line begins with the Go field name so godoc
// renders correctly.
func propertyDoc(goName, doc string) string {
	doc = cleanDoc(doc)
	if doc == "" {
		return ""
	}
	var b strings.Builder
	lines := strings.Split(doc, "\n")
	fmt.Fprintf(&b, "\t// %s %s\n", goName, lines[0])
	for _, l := range lines[1:] {
		if l == "" {
			b.WriteString("\t//\n")
		} else {
			fmt.Fprintf(&b, "\t// %s\n", l)
		}
	}
	return b.String()
}

// cleanDoc collapses leading/trailing whitespace per line and trims
// the whole block. Returns "" if the doc is effectively empty.
func cleanDoc(doc string) string {
	if doc == "" {
		return ""
	}
	// Normalise CRLF then trim.
	doc = strings.ReplaceAll(doc, "\r\n", "\n")
	doc = strings.TrimSpace(doc)
	if doc == "" {
		return ""
	}
	// Per-line whitespace trim — preserves intentional blank lines.
	lines := strings.Split(doc, "\n")
	for i, l := range lines {
		lines[i] = strings.TrimSpace(l)
	}
	return strings.Join(lines, "\n")
}
